import {JiboConfig, RobotInfo, DOFSets, DOFSet} from 'animation-utilities';
import {PromiseUtils as Async} from 'jibo-cai-utils';


/**
 * A representation of a set of Degrees of Freedom (DOFs).
 * @class DOFSet
 */

/**
 * Creates a new DOFSet containing all the DOFs of this
 * DOFSet, plus all the DOFs of the set passed in. Duplicates
 * are included only once (union of the sets).
 * @method DOFSet#plus
 * @param {DOFSet|string} otherSet - Set to add: either the name of the set or the actual DOFSet.
 * @returns {DOFSet} Union of this and `otherSet`.
 */

/**
 * Creates a new DOFSet containing all the DOFs of this
 * DOFSet that are not present in `otherSet`.
 * @method DOFSet#minus
 * @param {DOFSet|string} otherSet - Set to subtract: either the name of the set or the actual DOFSet.
 * @returns {DOFSet} DOFSet containing DOFs of this set that are not in the argument set.
 */

/**
 * Get the DOFs from this set as an array of strings.
 * @method DOFSet#getDOFs
 * @returns {string[]}
 */

/**
 * Check if this DOFSet contains a particular DOF.
 * @method DOFSet#hasDOF
 * @param {string} dofName - DOF name to test for membership in this set.
 * @returns {boolean} `true` if this DOFSet has this dof.
 */


export default async function createDOFs():Promise<DOFSets> {
    const config = new JiboConfig();
    const robotInfo = await Async.promisify<any>(
    cb => RobotInfo.createInfo(config, cb),
        false
    );
    /**
     * @interface DOFSets
     * @prop {DOFSet} ALL
     * @prop {DOFSet} BASE
     * @prop {DOFSet} BODY
     * @prop {DOFSet} EYE
     * @prop {DOFSet} LED
     * @prop {DOFSet} OVERLAY
     * @prop {DOFSet} SCREEN
     */
    return {
        ALL: robotInfo.getDOFSet("ALL") as DOFSet,
        BASE: robotInfo.getDOFSet("BASE") as DOFSet,
        BODY: robotInfo.getDOFSet("BODY") as DOFSet,
        EYE: robotInfo.getDOFSet("EYE") as DOFSet,
        LED: robotInfo.getDOFSet("LED") as DOFSet,
        OVERLAY: robotInfo.getDOFSet("OVERLAY") as DOFSet,
        SCREEN: robotInfo.getDOFSet("SCREEN") as DOFSet,
        EYE_ROOT: robotInfo.getDOFSet("EYE_ROOT") as DOFSet,
        EYE_DEFORM: robotInfo.getDOFSet("EYE_DEFORM") as DOFSet,
        EYE_RENDER: robotInfo.getDOFSet("EYE_RENDER") as DOFSet,
        EYE_TRANSLATE: robotInfo.getDOFSet("EYE_TRANSLATE") as DOFSet,
        EYE_ROTATE: robotInfo.getDOFSet("EYE_ROTATE") as DOFSet,
        EYE_COLOR: robotInfo.getDOFSet("EYE_COLOR") as DOFSet,
        EYE_TEXTURE: robotInfo.getDOFSet("EYE_TEXTURE") as DOFSet,
        EYE_VISIBILITY: robotInfo.getDOFSet("EYE_VISIBILITY") as DOFSet,
        OVERLAY_ROOT: robotInfo.getDOFSet("OVERLAY_ROOT") as DOFSet,
        OVERLAY_DEFORM: robotInfo.getDOFSet("OVERLAY_DEFORM") as DOFSet,
        OVERLAY_RENDER: robotInfo.getDOFSet("OVERLAY_RENDER") as DOFSet,
        OVERLAY_TRANSLATE: robotInfo.getDOFSet("OVERLAY_TRANSLATE") as DOFSet,
        OVERLAY_ROTATE: robotInfo.getDOFSet("OVERLAY_ROTATE") as DOFSet,
        OVERLAY_COLOR: robotInfo.getDOFSet("OVERLAY_COLOR") as DOFSet,
        OVERLAY_TEXTURE: robotInfo.getDOFSet("OVERLAY_TEXTURE") as DOFSet,
        OVERLAY_VISIBILITY: robotInfo.getDOFSet("OVERLAY_VISIBILITY") as DOFSet,
        SCREEN_BG_RENDER: robotInfo.getDOFSet("SCREEN_BG_RENDER") as DOFSet,
        SCREEN_BG_COLOR: robotInfo.getDOFSet("SCREEN_BG_COLOR") as DOFSet,
        SCREEN_BG_TEXTURE: robotInfo.getDOFSet("SCREEN_BG_TEXTURE") as DOFSet
    };
}
